const source = $input.first().json.body ?? $input.first().json;
const enabled = String($env.MEDIA_RABBITMQ_CANARY_ENABLED || 'false').trim().toLowerCase() === 'true';
const expectedToken = String($env.MEDIA_RABBITMQ_CANARY_TOKEN || '').trim();
const providedToken = String(source.canaryToken || '').trim();
const requestId = typeof source.requestId === 'string' && source.requestId.trim()
  ? source.requestId.trim()
  : `req-rabbitmq-canary-${Date.now()}`;

if (!enabled) {
  return [{ json: {
    route: 'blocked',
    responseCode: 423,
    requestId,
    ok: false,
    status: 'blocked',
    errorCode: 'RABBITMQ_CANARY_DISABLED',
    message: 'RabbitMQ canary workflow is staged but disabled. Set MEDIA_RABBITMQ_CANARY_ENABLED=true only after explicit approval.'
  } }];
}

if (!expectedToken || providedToken !== expectedToken) {
  return [{ json: {
    route: 'blocked',
    responseCode: 403,
    requestId,
    ok: false,
    status: 'blocked',
    errorCode: 'RABBITMQ_CANARY_UNAUTHORIZED',
    message: 'RabbitMQ canary token is missing or invalid.'
  } }];
}

if (source.confirm !== 'rabbitmq-canary-approved') {
  return [{ json: {
    route: 'blocked',
    responseCode: 400,
    requestId,
    ok: false,
    status: 'blocked',
    errorCode: 'RABBITMQ_CANARY_CONFIRMATION_REQUIRED',
    message: 'Set confirm to rabbitmq-canary-approved for a canary request.'
  } }];
}

return [{ json: {
  route: 'ready',
  responseCode: 202,
  requestId,
  ok: true,
  status: 'ready',
  canaryOnly: true,
  publishDisabled: true,
  dispatchMode: 'rabbitmq',
  profile: 'acestep_turbo',
  duration: 15,
  count: 1,
  message: 'RabbitMQ canary guard passed. Publish path is intentionally disabled in this staged workflow.'
} }];
